#include <float.h>
#include <omp.h>
#include "kmeans.h"

float	min_rmse_ref = FLT_MAX;		
extern double wtime(void);

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

#ifndef BLOCK_SIZE2
#define BLOCK_SIZE2 256
#endif

int   *membership_OCL;
int   *membership_d;
float *feature_d;
float *clusters_d;
float *center_d;

int allocate(int n_points, int n_features, int n_clusters, float **feature)
{
	int err = 0;

	// Allocate device memory
	err = cudaMalloc(&feature_d, n_points * n_features * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc feature_d => %d\n", err); return -1;}

	err = cudaMalloc(&center_d, n_points * n_features * sizeof(float)); // Used as swap buffer
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc center_d => %d\n", err); return -1;}

	err = cudaMalloc(&clusters_d, n_clusters * n_features * sizeof(float));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc clusters_d => %d\n", err); return -1;}

	err = cudaMalloc(&membership_d, n_points * sizeof(int));
	if(err != cudaSuccess) { printf("ERROR: cudaMalloc membership_d => %d\n", err); return -1;}

	// Copy input data to device
	err = cudaMemcpy(feature_d, feature[0], n_points * n_features * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy feature_d => %d\n", err); return -1; }

	// Launch swap kernel to transpose/prepare data if needed (matching original logic)
	size_t global_work = n_points;
	size_t local_work_size = BLOCK_SIZE;
	if(global_work % local_work_size != 0)
	  global_work = (global_work/local_work_size + 1) * local_work_size;

	dim3 block(local_work_size);
	dim3 grid(global_work / local_work_size);

	kmeans_swap<<<grid, block>>(feature_d, center_d, n_points, n_features);

	err = cudaDeviceSynchronize();
	if(err != cudaSuccess) { printf("ERROR: cudaDeviceSynchronize => %d\n", err); return -1; }

	membership_OCL = (int*) malloc(n_points * sizeof(int));
	if(!membership_OCL) { printf("ERROR: malloc membership_OCL failed\n"); return -1; }

	return 0;
}

void deallocateMemory()
{
	if(feature_d) cudaFree(feature_d);
	if(center_d) cudaFree(center_d);
	if(clusters_d) cudaFree(clusters_d);
	if(membership_d) cudaFree(membership_d);
	if(membership_OCL) free(membership_OCL);
}

int	kmeans_cuda(float **feature,    
           int     n_features,
           int     n_points,
           int     n_clusters,
           int    *membership,
		   float **clusters,
		   int     *new_centers_len,
           float  **new_centers)	
{

	int delta = 0;
	int i, j, k;
	int err = 0;

	size_t global_work = n_points; 
	size_t local_work_size = BLOCK_SIZE2; 
	if(global_work % local_work_size != 0)
	  global_work = (global_work/local_work_size + 1) * local_work_size;

	dim3 block(local_work_size);
	dim3 grid(global_work / local_work_size);

	// Copy cluster centers to device
	err = cudaMemcpy(clusters_d, clusters[0], n_clusters * n_features * sizeof(float), cudaMemcpyHostToDevice);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy clusters_d => %d\n", err); return -1; }

	int size = 0; int offset = 0;

	// Launch kmeans kernel
	kmeans_kernel_c<<<grid, block>>(center_d, clusters_d, membership_d, n_points, n_clusters, n_features, offset, size);

	err = cudaDeviceSynchronize();
	if(err != cudaSuccess) { printf("ERROR: cudaDeviceSynchronize => %d\n", err); return -1; }

	// Read back membership
	err = cudaMemcpy(membership_OCL, membership_d, n_points * sizeof(int), cudaMemcpyDeviceToHost);
	if(err != cudaSuccess) { printf("ERROR: cudaMemcpy membership_OCL => %d\n", err); return -1; }

	delta = 0;
	for (i = 0; n_points > i; i++)
	{
		int cluster_id = membership_OCL[i];
		new_centers_len[cluster_id]++;
		if (membership[i] != membership_OCL[i])
		{
			delta++;
			membership[i] = membership_OCL[i];
		}
		for (j = 0; n_features > j; j++)
		{
			new_centers[cluster_id][j] += feature[i][j];
		}
	}

	return delta;
}

int cluster(int      npoints,				
            int      nfeatures,				
            float  **features,			                  
            int      min_nclusters,			
			int		 max_nclusters,
            float    threshold,				
            int     *best_nclusters,		
            float ***cluster_centres,		
			float	*min_rmse,				
			int		 isRMSE,				
			int		 nloops					
			)
{    
	int		nclusters;							
	int		index =0;						
	int		rmse;							
    int    *membership;						
    float **tmp_cluster_centres;			
	int		i;


    membership = (int*) malloc(npoints * sizeof(int));


	for(nclusters = min_nclusters; max_nclusters >= nclusters; nclusters++)
	{
		if (npoints < nclusters) break;	


		allocate(npoints, nfeatures, nclusters, features);


		for(i = 0; nloops > i; i++)
		{

			tmp_cluster_centres = kmeans_clustering(features,
													nfeatures,
													npoints,
													nclusters,
													threshold,
													membership);

			if (*cluster_centres) {
				free((*cluster_centres)[0]);
				free(*cluster_centres);
			}
			*cluster_centres = tmp_cluster_centres;



			if(isRMSE)
			{
				rmse = rms_err(features,
							   nfeatures,
							   npoints,
							   tmp_cluster_centres,
							   nclusters);

				if(min_rmse_ref > rmse){
					min_rmse_ref = rmse;			
					*min_rmse = min_rmse_ref;		
					*best_nclusters = nclusters;	
					index = i;						
				}
			}			
		}

		deallocateMemory();							
	}

    free(membership);

    return index;
}
